import React, { useState, useEffect } from 'react';
import API from '../api/axios';
import Navigation from '../components/Navigation';

const UserMaster = () => {
    const [users, setUsers] = useState([]);
    const [formData, setFormData] = useState({
        userName: '', email: '', password: '', phoneNumber: '', role: 'User', department: '', programme: ''
    });
    const [loading, setLoading] = useState(false);
    const [departments, setDepartments] = useState([]);
    const [programmes, setProgrammes] = useState([]);
    const [message, setMessage] = useState('');

    const roleOptions = ['SuperAdmin', 'User', 'Networking Staff', 'Plumber', 'Electrician', 'Software Developer', 'Cleaner', 'Carpenter', 'panitiya', 'Other'];

    useEffect(() => {
        fetchUsers();
        fetchDepartments();
    }, []);

    const fetchUsers = async () => {
        try {
            const { data } = await API.get('/master/users');
            setUsers(data);
        } catch (err) {
            console.error('Error fetching users', err);
        }
    };

    const fetchDepartments = async () => {
        try {
            const { data } = await API.get('/master/department');
            setDepartments(data);
        } catch (err) {
            console.error('Error fetching departments', err);
        }
    };

    const fetchProgrammes = async (deptId) => {
        try {
            const { data } = await API.get('/master/programme');
            const filtered = data.filter(p => p.department && p.department._id === deptId);
            setProgrammes(filtered);
        } catch (err) {
            console.error('Error fetching programmes', err);
        }
    };

    const handleDepartmentChange = (e) => {
        const deptId = e.target.value;
        setFormData({ ...formData, department: deptId, programme: '' });
        if (deptId) fetchProgrammes(deptId);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            await API.post('/master/users', formData);
            setFormData({ userName: '', email: '', password: '', phoneNumber: '', role: 'User', department: '', programme: '' });
            fetchUsers();
            setMessage({ type: 'success', text: '✓ User created successfully!' });
            setTimeout(() => setMessage(''), 3000);
        } catch (err) {
            setMessage({ type: 'error', text: '✗ Error creating user' });
            setTimeout(() => setMessage(''), 3000);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={styles.pageWrapper}>
            <Navigation />
            <div style={styles.contentArea}>
                <div style={styles.headerSection}>
                    <h1 style={styles.mainTitle}>👤 User Master</h1>
                    <p style={styles.subtitle}>Create and manage user accounts</p>
                </div>

                {message && (
                    <div style={{
                        ...styles.alertBox,
                        background: message.type === 'success' ? 'rgba(16, 185, 129, 0.2)' : 'rgba(239, 68, 68, 0.2)',
                        borderColor: message.type === 'success' ? '#10b981' : '#ef4444',
                        color: message.type === 'success' ? '#a7f3d0' : '#fca5a5',
                    }}>
                        {message.text}
                    </div>
                )}

                <div style={styles.container}>
                    <div style={styles.formSide}>
                        <form onSubmit={handleSubmit} style={styles.form}>
                            <div style={styles.formGrid}>
                                <div style={styles.formGroup}>
                                    <label style={styles.label}>👤 Username</label>
                                    <input
                                        type="text"
                                        placeholder="Enter username..."
                                        required
                                        value={formData.userName}
                                        onChange={e => setFormData({ ...formData, userName: e.target.value })}
                                        style={styles.input}
                                    />
                                </div>

                                <div style={styles.formGroup}>
                                    <label style={styles.label}>📧 Email</label>
                                    <input
                                        type="email"
                                        placeholder="Enter email..."
                                        required
                                        value={formData.email}
                                        onChange={e => setFormData({ ...formData, email: e.target.value })}
                                        style={styles.input}
                                    />
                                </div>

                                <div style={styles.formGroup}>
                                    <label style={styles.label}>🔐 Password</label>
                                    <input
                                        type="password"
                                        placeholder="Enter password..."
                                        required
                                        value={formData.password}
                                        onChange={e => setFormData({ ...formData, password: e.target.value })}
                                        style={styles.input}
                                    />
                                </div>

                                <div style={styles.formGroup}>
                                    <label style={styles.label}>📱 Phone Number</label>
                                    <input
                                        type="tel"
                                        placeholder="10-digit phone..."
                                        required
                                        value={formData.phoneNumber}
                                        onChange={e => setFormData({ ...formData, phoneNumber: e.target.value })}
                                        style={styles.input}
                                    />
                                </div>

                                <div style={styles.formGroup}>
                                    <label style={styles.label}>👔 Role</label>
                                    <select
                                        required
                                        value={formData.role}
                                        onChange={e => setFormData({ ...formData, role: e.target.value })}
                                        style={styles.input}
                                    >
                                        {roleOptions.map(role => (
                                            <option key={role} value={role}>{role}</option>
                                        ))}
                                    </select>
                                </div>

                                <div style={styles.formGroup}>
                                    <label style={styles.label}>🏢 Department</label>
                                    <select
                                        value={formData.department}
                                        onChange={handleDepartmentChange}
                                        style={styles.input}
                                    >
                                        <option value="">Select Department</option>
                                        {departments.map(dept => (
                                            <option key={dept._id} value={dept._id}>{dept.deptName}</option>
                                        ))}
                                    </select>
                                </div>

                                {formData.department && (
                                    <div style={styles.formGroup}>
                                        <label style={styles.label}>📚 Programme</label>
                                        <select
                                            value={formData.programme}
                                            onChange={e => setFormData({ ...formData, programme: e.target.value })}
                                            style={styles.input}
                                        >
                                            <option value="">Select Programme</option>
                                            {programmes.map(prog => (
                                                <option key={prog._id} value={prog._id}>{prog.programmeName}</option>
                                            ))}
                                        </select>
                                    </div>
                                )}
                            </div>

                            <button type="submit" disabled={loading} style={{ ...styles.button, opacity: loading ? 0.6 : 1 }}>
                                {loading ? '⏳ Creating...' : '➕ Create User'}
                            </button>
                        </form>
                    </div>

                    <div style={styles.tableSide}>
                        <h3 style={styles.tableTitle}>📋 Users List</h3>
                        <div style={styles.tableContainer}>
                            <table style={styles.table}>
                                <thead>
                                    <tr style={styles.tableHeaderRow}>
                                        <th style={{ ...styles.tableHeader, width: '20%' }}>Username</th>
                                        <th style={{ ...styles.tableHeader, width: '20%' }}>Email</th>
                                        <th style={{ ...styles.tableHeader, width: '15%' }}>Phone</th>
                                        <th style={{ ...styles.tableHeader, width: '15%' }}>Role</th>
                                        <th style={{ ...styles.tableHeader, width: '15%' }}>Dept</th>
                                        <th style={{ ...styles.tableHeader, width: '15%' }}>Prog</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {users.length > 0 ? (
                                        users.map((user, idx) => (
                                            <tr key={user._id} style={idx % 2 === 0 ? styles.tableRowEven : styles.tableRowOdd}>
                                                <td style={styles.tableCell}>
                                                    <span style={styles.userBadge}>💼</span> {user.userName}
                                                </td>
                                                <td style={styles.tableCell}>{user.email}</td>
                                                <td style={styles.tableCell}>{user.phoneNumber || '-'}</td>
                                                <td style={styles.tableCell}>
                                                    <span style={{ ...styles.roleBadge, background: getRoleColor(user.role) }}>{user.role}</span>
                                                </td>
                                                <td style={styles.tableCell}>{user.department?.deptName || '-'}</td>
                                                <td style={styles.tableCell}>{user.programme?.programmeName || '-'}</td>
                                            </tr>
                                        ))
                                    ) : (
                                        <tr>
                                            <td colSpan="6" style={{ ...styles.tableCell, textAlign: 'center', color: '#94a3b8' }}>
                                                No users found
                                            </td>
                                        </tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

const getRoleColor = (role) => {
    const colors = {
        'SuperAdmin': 'linear-gradient(135deg, #ef4444, #dc2626)',
        'User': 'linear-gradient(135deg, #38bdf8, #06b6d4)',
        'Networking Staff': 'linear-gradient(135deg, #8b5cf6, #7c3aed)',
        'Plumber': 'linear-gradient(135deg, #f59e0b, #d97706)',
        'Electrician': 'linear-gradient(135deg, #10b981, #059669)',
        'Software Developer': 'linear-gradient(135deg, #6366f1, #4f46e5)',
    };
    return colors[role] || 'linear-gradient(135deg, #38bdf8, #818cf8)';
};

const styles = {
    pageWrapper: { minHeight: '100vh', background: 'linear-gradient(135deg, #0f172a 0%, #1a1f35 50%, #0f172a 100%)', color: '#e0e7ff', fontFamily: "'Poppins', sans-serif" },
    contentArea: { maxWidth: '1600px', margin: '0 auto', padding: '40px 30px' },
    headerSection: { marginBottom: '40px' },
    mainTitle: { fontSize: '2.2rem', fontWeight: 800, background: 'linear-gradient(135deg, #38bdf8, #818cf8)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', backgroundClip: 'text', marginBottom: '10px' },
    subtitle: { fontSize: '1rem', color: '#94a3b8', fontWeight: 500 },
    alertBox: { padding: '16px 20px', borderRadius: '12px', border: '2px solid', marginBottom: '30px', fontWeight: 600 },
    container: { display: 'grid', gridTemplateColumns: '1fr 2fr', gap: '30px', alignItems: 'start' },
    formSide: { background: 'linear-gradient(135deg, rgba(30, 41, 59, 0.5), rgba(30, 41, 59, 0.2))', backdropFilter: 'blur(15px)', border: '2px solid rgba(51, 65, 85, 0.3)', borderRadius: '16px', padding: '28px', boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.25)' },
    form: { display: 'flex', flexDirection: 'column', gap: '20px' },
    formGrid: { display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '16px' },
    formGroup: { display: 'flex', flexDirection: 'column' },
    label: { fontSize: '0.95rem', fontWeight: 600, color: '#cbd5e1', marginBottom: '8px', letterSpacing: '0.3px' },
    input: { padding: '12px 16px', background: 'rgba(20, 28, 45, 0.6)', border: '2px solid rgba(51, 65, 85, 0.4)', borderRadius: '12px', color: '#fff', fontSize: '0.95rem', fontFamily: "'Poppins', sans-serif", transition: 'all 0.3s ease', boxSizing: 'border-box', cursor: 'pointer' },
    button: { padding: '14px 24px', background: 'linear-gradient(135deg, #38bdf8, #818cf8)', border: 'none', borderRadius: '12px', color: 'white', fontSize: '0.95rem', fontWeight: 700, cursor: 'pointer', transition: 'all 0.3s ease', fontFamily: "'Poppins', sans-serif", boxShadow: '0 10px 30px -8px rgba(56, 189, 248, 0.3)', marginTop: '10px' },
    tableSide: { background: 'linear-gradient(135deg, rgba(30, 41, 59, 0.5), rgba(30, 41, 59, 0.2))', backdropFilter: 'blur(15px)', border: '2px solid rgba(51, 65, 85, 0.3)', borderRadius: '16px', padding: '28px', boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.25)' },
    tableTitle: { fontSize: '1.3rem', fontWeight: 700, color: '#e0e7ff', marginBottom: '20px' },
    tableContainer: { overflowX: 'auto' },
    table: { width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' },
    tableHeaderRow: { background: 'linear-gradient(135deg, rgba(56, 189, 248, 0.1), rgba(129, 140, 248, 0.1))' },
    tableHeader: { padding: '12px 12px', textAlign: 'left', color: '#e0e7ff', fontWeight: 700, fontSize: '0.85rem', borderBottom: '2px solid rgba(51, 65, 85, 0.3)', letterSpacing: '0.5px', textTransform: 'uppercase' },
    tableRowEven: { background: 'rgba(56, 189, 248, 0.05)' },
    tableRowOdd: { background: 'transparent' },
    tableCell: { padding: '12px 12px', borderBottom: '1px solid rgba(51, 65, 85, 0.2)', color: '#cbd5e1', fontSize: '0.9rem' },
    userBadge: { marginRight: '6px' },
    roleBadge: { display: 'inline-block', color: 'white', padding: '3px 10px', borderRadius: '16px', fontSize: '0.7rem', fontWeight: 700, textTransform: 'uppercase' },
};

export default UserMaster;
